content:
{
  "sentences": [
    {
      "text": "你好，我想要一杯小杯拿鐵，可以嗎？",
      "pinyin": "Nǐ hǎo, wǒ xiǎng yào yī bēi xiǎo bēi nátiě, kěyǐ ma?",
      "pinyin_numeric": "ni3 hao3, wo3 xiang3 yao4 yi1 bei1 xiao3 bei1 na2tie3, ke3yi3 ma0?",
      "translation_en": "Hello, I would like a small latte, okay?",
      "translation_ko": "안녕하세요, 작은 라떼 한 잔을 원하는데 괜찮을까요?"
    },
    {
      "text": "麻煩你，可以給我一個袋子嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī ge dàizi ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 ge4 dai4zi0 ma0?",
      "translation_en": "Excuse me, can you give me a bag?",
      "translation_ko": "실례합니다, 봉투 하나 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以幫我加珍珠嗎？",
      "pinyin": "Bù hǎo yìsi, kěyǐ bāng wǒ jiā zhēnzhū ma?",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 bang1 wo3 jia1 zhen1zhu1 ma0?",
      "translation_en": "Excuse me, can you add pearls for me?",
      "translation_ko": "죄송합니다, 타피오카 펄을 추가해 주실 수 있나요?"
    },
    {
      "text": "店員，可以給我菜單看一下嗎？",
      "pinyin": "Diànyuán, kěyǐ gěi wǒ càidān kàn yīxià ma?",
      "pinyin_numeric": "dian4yuan2, ke3yi3 gei3 wo3 cai4dan1 kan4 yi1xia4 ma0?",
      "translation_en": "Staff, can you let me take a look at the menu?",
      "translation_ko": "직원분, 메뉴판 좀 볼 수 있을까요?"
    },
    {
      "text": "我想要一杯大杯紅茶，半糖少冰，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi dà bēi hóngchá, bàn táng shǎo bīng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 da4 bei1 hong2cha2, ban4 tang2 shao3 bing1, ke3yi3 ma0?",
      "translation_en": "I would like a large black tea, half sugar and less ice, okay?",
      "translation_ko": "큰 홍차 한 잔, 반당에 얼음 적게 해 주실 수 있나요?"
    },
    {
      "text": "不好意思，可以再說一次嗎？我聽不懂。",
      "pinyin": "Bù hǎo yìsi, kěyǐ zài shuō yī cì ma? Wǒ tīng bù dǒng.",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 zai4 shuo1 yi1 ci4 ma0? wo3 ting1 bu4 dong3.",
      "translation_en": "Excuse me, can you say it again? I don't understand.",
      "translation_ko": "죄송합니다, 한 번 더 말씀해 주시겠어요? 제가 못 알아들었어요."
    },
    {
      "text": "麻煩你，可以給我一根吸管嗎？",
      "pinyin": "Máfan nǐ, kěyǐ gěi wǒ yī gēn xīguǎn ma?",
      "pinyin_numeric": "ma2fan2 ni3, ke3yi3 gei3 wo3 yi1 gen1 xi1guan3 ma0?",
      "translation_en": "Excuse me, can you give me a straw?",
      "translation_ko": "실례합니다, 빨대 하나 주실 수 있나요?"
    },
    {
      "text": "客人，可以等一下嗎？馬上就好。",
      "pinyin": "Kèrén, kěyǐ děng yīxià ma? Mǎshàng jiù hǎo.",
      "pinyin_numeric": "ke4ren2, ke3yi3 deng3 yi1xia4 ma0? ma3shang4 jiu4 hao3.",
      "translation_en": "Customer, can you wait a moment? It will be ready soon.",
      "translation_ko": "손님, 잠시만 기다려 주시겠어요? 곧 준비됩니다."
    },
    {
      "text": "我想要一杯綠茶，去冰，內用，可以嗎？",
      "pinyin": "Wǒ xiǎng yào yī bēi lǜchá, qù bīng, nèi yòng, kěyǐ ma?",
      "pinyin_numeric": "wo3 xiang3 yao4 yi1 bei1 lü4cha2, qu4 bing1, nei4 yong4, ke3yi3 ma0?",
      "translation_en": "I would like a green tea, no ice, for here, okay?",
      "translation_ko": "녹차 한 잔, 얼음 빼고 매장에서 마실게요, 괜찮을까요?"
    },
    {
      "text": "不好意思，可以給我發票嗎？謝謝。",
      "pinyin": "Bù hǎo yìsi, kěyǐ gěi wǒ fāpiào ma? Xièxie.",
      "pinyin_numeric": "bu4 hao3 yi4si0, ke3yi3 gei3 wo3 fa1piao4 ma0? xie4xie0.",
      "translation_en": "Excuse me, can you give me the receipt? Thank you.",
      "translation_ko": "죄송합니다, 영수증 주실 수 있나요? 감사합니다."
    }
  ]
}
